## 安裝
```bash
# 裝 .NET 8 SDK（https://dotnet.microsoft.com）
dotnet --version
```

## 建專案
```bash
dotnet new webapi -n MyApp
cd MyApp
dotnet run
```

## Minimal API（最簡單）
```csharp
var builder = WebApplication.CreateBuilder(args);
var app = builder.Build();

app.MapGet("/", () => "Hello, World!");

app.MapGet("/users/{id}", (int id) => new { id, name = "Alice" });

app.MapPost("/users", (User user) => {
    return Results.Created($"/users/{user.Id}", user);
});

app.Run();

record User(int Id, string Name);
```

## Controller-based
```csharp
[ApiController]
[Route("api/[controller]")]
public class UsersController : ControllerBase
{
    private readonly UserService _service;

    public UsersController(UserService service)
    {
        _service = service;
    }

    [HttpGet]
    public async Task<IEnumerable<User>> GetAll()
    {
        return await _service.GetAllAsync();
    }

    [HttpGet("{id}")]
    public async Task<ActionResult<User>> GetById(int id)
    {
        var user = await _service.GetByIdAsync(id);
        if (user == null) return NotFound();
        return user;
    }

    [HttpPost]
    public async Task<ActionResult<User>> Create(CreateUserDto dto)
    {
        var user = await _service.CreateAsync(dto);
        return CreatedAtAction(nameof(GetById), new { id = user.Id }, user);
    }
}
```

## EF Core（ORM）
```csharp
public class User
{
    public int Id { get; set; }
    public string Email { get; set; }
    public string Name { get; set; }
    public DateTime CreatedAt { get; set; }
}

public class AppDbContext : DbContext
{
    public DbSet<User> Users { get; set; }

    protected override void OnConfiguring(DbContextOptionsBuilder options)
    {
        options.UseNpgsql("Host=localhost;Database=mydb");
    }
}
```

```csharp
var users = await db.Users
    .Where(u => u.CreatedAt > DateTime.UtcNow.AddDays(-7))
    .OrderBy(u => u.Name)
    .ToListAsync();

await db.Users.AddAsync(new User { Email = "...", Name = "..." });
await db.SaveChangesAsync();
```

## Migration
```bash
dotnet ef migrations add CreateUsers
dotnet ef database update
```

## DI（Dependency Injection）
```csharp
// Program.cs
builder.Services.AddDbContext<AppDbContext>();
builder.Services.AddScoped<UserService>();

// Service
public class UserService
{
    private readonly AppDbContext _db;

    public UserService(AppDbContext db) => _db = db;

    public async Task<List<User>> GetAllAsync() => await _db.Users.ToListAsync();
}
```

## Validation
```csharp
public class CreateUserDto
{
    [Required]
    [EmailAddress]
    public string Email { get; set; }

    [Required]
    [MinLength(2)]
    public string Name { get; set; }
}
```

## 部署
```bash
dotnet publish -c Release -o ./publish

# Docker
FROM mcr.microsoft.com/dotnet/aspnet:8.0
COPY publish/ .
ENTRYPOINT ["dotnet", "MyApp.dll"]
```

